import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, FormsModule, ReactiveFormsModule, Validators } from '@angular/forms';
import { AlumnoService } from '../../../core/services/alumno.service';
import { AlumnoRequest, AlumnoResponse } from '../../../core/models/alumno.model';
import { ReportesService } from '../../../core/services/reportes.service';
import { ToastService } from '../../../core/services/toast.service';
import { ConfirmModalComponent } from '../../../core/components/confirm-modal/confirm-modal.component';
import { getSubscriptionClass } from '../../../core/utils/subscription.utils';

@Component({
  selector: 'app-alumnos',
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    ReactiveFormsModule,
    ConfirmModalComponent
  ],
  templateUrl: './alumnos.component.html',
  styleUrls: ['./alumnos.component.css']
})
export class AlumnosComponent implements OnInit {
  private alumnoService = inject(AlumnoService);
  private reportesService = inject(ReportesService);
  private fb = inject(FormBuilder);
  private toastService = inject(ToastService);

  exportarCSV(): void {
    this.reportesService.exportarAlumnos().subscribe({
      error: (err) => {
        console.error('Error al exportar alumnos:', err);
      }
    });
  }

  alumnos: AlumnoResponse[] = [];
  filteredAlumnos: AlumnoResponse[] = [];
  searchQuery = '';
  currentPage = 1;
  readonly pageSize = 10;

  // Modal controls
  showCreateEditModal = false;
  showDetailModal = false;
  isEditMode = false;
  isFormSubmitting = false;
  modalErrorMsg = '';

  // Confirm modal controls
  showConfirmModal = false;
  confirmModalType: 'success' | 'danger' | 'info' | 'warning' = 'warning';
  confirmModalTitle = '';
  confirmModalMessage = '';
  pendingAlumnoAction: (() => void) | null = null;

  selectedAlumno: AlumnoResponse | null = null;

  alumnoForm: FormGroup = this.fb.group({
    nombres: ['', [Validators.required, Validators.minLength(2), Validators.maxLength(100), Validators.pattern('^[a-zA-ZáéíóúÁÉÍÓÚñÑ ]+$')]],
    apellidos: ['', [Validators.required, Validators.minLength(2), Validators.maxLength(100), Validators.pattern('^[a-zA-ZáéíóúÁÉÍÓÚñÑ ]+$')]],
    correo: ['', [Validators.required, Validators.email, Validators.maxLength(150)]],
    telefono: ['', [Validators.pattern('^[0-9]{9}$')]],
    nivelSuscripcionId: [1, [Validators.required]],
    password: ['', [Validators.minLength(6)]],
    estado: [true]
  });

  ngOnInit(): void {
    this.loadAlumnos();
  }

  loadAlumnos(): void {
    this.alumnoService.listarAlumnos().subscribe({
      next: (data) => {
        this.alumnos = data;
        this.applyFilter();
      },
      error: (err) => {
        console.error('Error al listar alumnos', err);
      }
    });
  }

  applyFilter(): void {
    if (!this.searchQuery.trim()) {
      this.filteredAlumnos = [...this.alumnos];
      this.currentPage = 1;
      return;
    }

    const query = this.searchQuery.toLowerCase();
    this.filteredAlumnos = this.alumnos.filter(a => 
      a.nombres.toLowerCase().includes(query) ||
      a.apellidos.toLowerCase().includes(query) ||
      a.correo.toLowerCase().includes(query)
    );
    this.currentPage = 1;
  }

  get totalPages(): number {
    return Math.max(1, Math.ceil(this.filteredAlumnos.length / this.pageSize));
  }

  get paginatedAlumnos(): AlumnoResponse[] {
    const start = (this.currentPage - 1) * this.pageSize;
    return this.filteredAlumnos.slice(start, start + this.pageSize);
  }

  goToPage(page: number): void {
    if (page < 1 || page > this.totalPages) return;
    this.currentPage = page;
  }

  nextPage(): void {
    this.goToPage(this.currentPage + 1);
  }

  previousPage(): void {
    this.goToPage(this.currentPage - 1);
  }

  trackByAlumnoId(_: number, alumno: AlumnoResponse): number {
    return alumno.id;
  }

  openCreateModal(): void {
    this.isEditMode = false;
    this.modalErrorMsg = '';
    this.selectedAlumno = null;
    this.alumnoForm.reset({
      nombres: '',
      apellidos: '',
      correo: '',
      telefono: '',
      nivelSuscripcionId: 1,
      estado: true
    });
    this.showCreateEditModal = true;
  }

  openEditModal(alumno: AlumnoResponse): void {
    this.isEditMode = true;
    this.modalErrorMsg = '';
    this.selectedAlumno = alumno;
    
    // Map subscription name back to numeric ID
    let subId = 1;
    if (alumno.nivelSuscripcion === 'INTERMEDIO') {
      subId = 2;
    } else if (alumno.nivelSuscripcion === 'PREMIUM') {
      subId = 3;
    }

    this.alumnoForm.patchValue({
      nombres: alumno.nombres,
      apellidos: alumno.apellidos,
      correo: alumno.correo,
      telefono: alumno.telefono,
      nivelSuscripcionId: subId,
      estado: alumno.estado
    });
    this.showCreateEditModal = true;
  }

  closeCreateEditModal(): void {
    this.showCreateEditModal = false;
    this.isFormSubmitting = false;
  }

  openDetailModal(alumno: AlumnoResponse): void {
    this.selectedAlumno = alumno;
    this.showDetailModal = true;
  }

  closeDetailModal(): void {
    this.showDetailModal = false;
    this.selectedAlumno = null;
  }

  toggleEstado(alumno: AlumnoResponse): void {
    const nuevoEstado = !alumno.estado;
    const accion = nuevoEstado ? 'Activar' : 'Desactivar';
    
    this.confirmModalType = nuevoEstado ? 'success' : 'danger';
    this.confirmModalTitle = `¿${accion} Alumno?`;
    this.confirmModalMessage = `¿Estás seguro de que deseas ${accion.toLowerCase()} la cuenta del alumno ${alumno.nombres} ${alumno.apellidos}?`;
    
    this.pendingAlumnoAction = () => {
      this.alumnoService.cambiarEstado(alumno.id, nuevoEstado).subscribe({
        next: () => {
          alumno.estado = nuevoEstado;
          this.toastService.success(`Alumno ${nuevoEstado ? 'activado' : 'desactivado'} exitosamente.`);
          this.showConfirmModal = false;
        },
        error: (err) => {
          this.toastService.error(err.error?.message || 'Error al cambiar el estado del alumno.');
          this.showConfirmModal = false;
        }
      });
    };
    
    this.showConfirmModal = true;
  }

  confirmAction(): void {
    if (this.pendingAlumnoAction) {
      this.pendingAlumnoAction();
    }
  }

  onSubmit(): void {
    if (this.alumnoForm.invalid) {
      this.alumnoForm.markAllAsTouched();
      this.toastService.warning('Por favor complete todos los campos requeridos correctamente.');
      return;
    }

    this.isFormSubmitting = true;
    this.modalErrorMsg = '';

    const req: AlumnoRequest = {
      nombres: this.alumnoForm.value.nombres,
      apellidos: this.alumnoForm.value.apellidos,
      correo: this.alumnoForm.value.correo,
      telefono: this.alumnoForm.value.telefono || '',
      nivelSuscripcionId: Number(this.alumnoForm.value.nivelSuscripcionId),
      password: this.alumnoForm.value.password || undefined
    };

    if (this.isEditMode && this.selectedAlumno) {
      this.alumnoService.editarAlumno(this.selectedAlumno.id, req).subscribe({
        next: () => {
          // Check if state changed, and update via PATCH since backend PUT doesn't update state
          const stateChanged = this.alumnoForm.value.estado !== this.selectedAlumno!.estado;
          if (stateChanged) {
            this.alumnoService.cambiarEstado(this.selectedAlumno!.id, this.alumnoForm.value.estado).subscribe({
              next: () => {
                this.loadAlumnos();
                this.toastService.success('Datos de alumno y estado actualizados exitosamente.');
                this.closeCreateEditModal();
              },
              error: (err) => this.handleError(err)
            });
          } else {
            this.loadAlumnos();
            this.toastService.success('Datos de alumno actualizados exitosamente.');
            this.closeCreateEditModal();
          }
        },
        error: (err) => this.handleError(err)
      });
    } else {
      this.alumnoService.crearAlumno(req).subscribe({
        next: () => {
          this.loadAlumnos();
          this.toastService.success('Alumno registrado exitosamente.');
          this.closeCreateEditModal();
        },
        error: (err) => this.handleError(err)
      });
    }
  }

  private handleError(err: any): void {
    this.isFormSubmitting = false;
    this.modalErrorMsg = err.error?.message || 'Ocurrió un error inesperado al procesar la solicitud.';
    this.toastService.error(this.modalErrorMsg, 'Error en el Servidor');
  }

  getSubscriptionClass = getSubscriptionClass;
}
<div class="space-y-6 font-body">
  <!-- Top Bar -->
  <div class="border border-slate-200 dark:border-slate-800 p-4 md:p-6 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex flex-col gap-4 md:flex-row md:justify-between md:items-center transition-colors duration-300">
    <div>
      <h1 class="text-xl md:text-2xl font-black text-slate-900 dark:text-white tracking-tight uppercase">Gestión de Alumnos</h1>
      <p class="text-slate-500 dark:text-slate-400 text-xs mt-1">Control de alumnos inscritos, estado de cuentas y niveles de suscripción.</p>
    </div>
    <div class="flex flex-col gap-2 md:flex-row md:gap-2 w-full md:w-auto">
      <button 
        (click)="exportarCSV()" 
        class="flex items-center justify-center gap-2 px-4 py-2.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors duration-305 rounded-none w-full md:w-auto">
        <span class="material-symbols-outlined text-sm">download</span>
        <span>Exportar CSV</span>
      </button>
      <button 
        (click)="openCreateModal()" 
        class="flex items-center justify-center gap-2 px-4 py-2.5 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-widest hover:bg-slate-800 dark:hover:bg-slate-200 transition-colors duration-300 rounded-none w-full md:w-auto">
        <span class="material-symbols-outlined text-sm">add</span>
        <span>Crear Alumno</span>
      </button>
    </div>
  </div>

  <!-- Main Content Card / Table -->
  <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] overflow-hidden transition-colors duration-300">
    <!-- Filter bar -->
    <div class="p-4 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900 flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between transition-colors duration-300">
      <div class="relative w-full">
        <span class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400 dark:text-slate-500">
          <span class="material-symbols-outlined text-base">search</span>
        </span>
        <input 
          [(ngModel)]="searchQuery"
          (input)="applyFilter()"
          class="block w-full pl-9 pr-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 placeholder-slate-400 dark:placeholder-slate-500 focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary text-xs rounded-none transition-colors duration-300" 
          placeholder="Buscar por nombre o correo...">
      </div>
      <span class="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider whitespace-nowrap">
        {{ filteredAlumnos.length }} alumnos encontrados
      </span>
    </div>

    <!-- MOBILE: Card Stack (hidden on md+) -->
    <div class="md:hidden divide-y divide-slate-100 dark:divide-slate-800">
      <!-- Mobile Empty State -->
      <div *ngIf="filteredAlumnos.length === 0" class="p-10 text-center text-slate-400 dark:text-slate-500">
        <span class="material-symbols-outlined text-4xl mb-2 text-slate-300 dark:text-slate-700">group_off</span>
        <p class="font-medium text-xs">No se encontraron alumnos registrados.</p>
      </div>
      <!-- Mobile Cards -->
      <div *ngFor="let alumno of paginatedAlumnos; trackBy: trackByAlumnoId" class="p-4 space-y-3 bg-white dark:bg-slate-900 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors duration-300">
        <div class="flex items-start justify-between gap-2">
          <div>
            <p class="font-bold text-slate-900 dark:text-white text-sm leading-tight">{{ alumno.nombres }} {{ alumno.apellidos }}</p>
            <p class="text-xs text-slate-500 dark:text-slate-400 mt-0.5 break-all">{{ alumno.correo }}</p>
          </div>
          <span [ngClass]="alumno.estado ? 'bg-emerald-50 text-emerald-700 border-emerald-300 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900' : 'bg-red-50 text-red-700 border-red-300 dark:bg-red-950/30 dark:text-red-400 dark:border-red-900'" class="px-2 py-0.5 text-[9px] font-black uppercase tracking-wider border rounded-none shrink-0">
            {{ alumno.estado ? 'ACTIVO' : 'INACTIVO' }}
          </span>
        </div>
        <div class="flex items-center justify-between gap-2">
          <span [ngClass]="getSubscriptionClass(alumno.nivelSuscripcion)" class="px-2.5 py-1 text-[9px] font-black uppercase tracking-wider rounded-none">
            {{ alumno.nivelSuscripcion }}
          </span>
          <div class="inline-flex gap-2">
            <button 
              (click)="openDetailModal(alumno)" 
              title="Ver Detalle"
              class="p-1.5 border border-slate-200 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-none transition-colors duration-300">
              <span class="material-symbols-outlined text-base block">visibility</span>
            </button>
            <button 
              (click)="openEditModal(alumno)" 
              title="Editar Alumno"
              class="p-1.5 border border-slate-200 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-none transition-colors duration-300">
              <span class="material-symbols-outlined text-base block">edit</span>
            </button>
            <button 
              (click)="toggleEstado(alumno)" 
              [title]="alumno.estado ? 'Desactivar' : 'Activar'"
              [ngClass]="alumno.estado ? 'border-red-200 dark:border-red-900/60 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-950/20' : 'border-emerald-200 dark:border-emerald-900/60 text-emerald-600 dark:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-950/20'"
              class="p-1.5 border rounded-none transition-colors">
              <span class="material-symbols-outlined text-base block">
                {{ alumno.estado ? 'block' : 'check_circle' }}
              </span>
            </button>
          </div>
        </div>
      </div>
    </div>

    <!-- DESKTOP: Full Table (hidden on mobile, visible on md+) -->
    <div class="hidden md:block overflow-x-auto">
      <table class="w-full text-left border-collapse text-xs">
        <thead>
          <tr class="border-b border-slate-200 dark:border-slate-800 bg-slate-100/60 dark:bg-slate-800/40 text-slate-700 dark:text-slate-300 font-bold uppercase tracking-wider text-[10px] transition-colors duration-300">
            <th class="p-4">Nombre Completo</th>
            <th class="p-4">Correo Electrónico</th>
            <th class="p-4">Suscripción</th>
            <th class="p-4">Estado</th>
            <th class="p-4 text-right">Acciones</th>
          </tr>
        </thead>
        <tbody class="divide-y divide-slate-100 dark:divide-slate-800">
          <!-- Empty State -->
          <tr *ngIf="filteredAlumnos.length === 0">
            <td colspan="5" class="p-12 text-center text-slate-400 dark:text-slate-500">
              <span class="material-symbols-outlined text-4xl mb-2 text-slate-300 dark:text-slate-700">group_off</span>
              <p class="font-medium text-xs">No se encontraron alumnos registrados.</p>
            </td>
          </tr>
          <!-- Rows -->
          <tr *ngFor="let alumno of paginatedAlumnos; trackBy: trackByAlumnoId" class="hover:bg-slate-50/50 dark:hover:bg-slate-800/20 transition-colors duration-300">
            <td class="p-4 font-bold text-slate-900 dark:text-white">
              {{ alumno.nombres }} {{ alumno.apellidos }}
            </td>
            <td class="p-4 text-slate-600 dark:text-slate-400">
              {{ alumno.correo }}
            </td>
            <td class="p-4">
              <span [ngClass]="getSubscriptionClass(alumno.nivelSuscripcion)" class="px-2.5 py-1 text-[9px] font-black uppercase tracking-wider rounded-none">
                {{ alumno.nivelSuscripcion }}
              </span>
            </td>
            <td class="p-4">
              <span [ngClass]="alumno.estado ? 'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-950/30 dark:text-emerald-450 dark:border-emerald-900' : 'bg-red-50 text-red-700 border-red-200 dark:bg-red-950/30 dark:text-red-450 dark:border-red-900'" class="px-2.5 py-1 text-[9px] font-black uppercase tracking-wider border rounded-none">
                {{ alumno.estado ? 'ACTIVO' : 'INACTIVO' }}
              </span>
            </td>
            <td class="p-4 text-right">
              <div class="inline-flex gap-2">
                <button 
                  (click)="openDetailModal(alumno)" 
                  title="Ver Detalle"
                  class="p-1.5 border border-slate-200 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-none transition-colors duration-300">
                  <span class="material-symbols-outlined text-base block">visibility</span>
                </button>
                <button 
                  (click)="openEditModal(alumno)" 
                  title="Editar Alumno"
                  class="p-1.5 border border-slate-200 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-none transition-colors duration-300">
                  <span class="material-symbols-outlined text-base block">edit</span>
                </button>
                <button 
                  (click)="toggleEstado(alumno)" 
                  [title]="alumno.estado ? 'Desactivar' : 'Activar'"
                  [ngClass]="alumno.estado ? 'border-red-200 dark:border-red-900/60 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-950/20' : 'border-emerald-200 dark:border-emerald-900/60 text-emerald-600 dark:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-950/20'"
                  class="p-1.5 border rounded-none transition-colors">
                  <span class="material-symbols-outlined text-base block">
                    {{ alumno.estado ? 'block' : 'check_circle' }}
                  </span>
                </button>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
    </div>

    <!-- Pagination -->
    <div *ngIf="filteredAlumnos.length > pageSize" class="px-4 py-4 border-t border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between transition-colors duration-300">
      <div class="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
        Página {{ currentPage }} de {{ totalPages }}
      </div>

      <div class="flex items-center gap-2 flex-wrap">
        <button
          type="button"
          (click)="previousPage()"
          [disabled]="currentPage === 1"
          class="px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-[10px] uppercase tracking-widest hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors disabled:opacity-40 disabled:cursor-not-allowed rounded-none">
          Anterior
        </button>

        <button
          *ngFor="let page of [].constructor(totalPages); let i = index"
          type="button"
          (click)="goToPage(i + 1)"
          [ngClass]="currentPage === (i + 1) ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 border-slate-900 dark:border-slate-100' : 'bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 border-slate-300 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700'"
          class="w-10 h-10 border font-black text-[10px] uppercase tracking-widest transition-colors rounded-none">
          {{ i + 1 }}
        </button>

        <button
          type="button"
          (click)="nextPage()"
          [disabled]="currentPage === totalPages"
          class="px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-[10px] uppercase tracking-widest hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors disabled:opacity-40 disabled:cursor-not-allowed rounded-none">
          Siguiente
        </button>
      </div>
    </div>
  </div>

  <!-- Create/Edit Modal -->
  <div *ngIf="showCreateEditModal" role="dialog" aria-modal="true" class="fixed inset-0 bg-slate-900/60 dark:bg-slate-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4" (click)="closeCreateEditModal()">
    <div class="w-full max-w-lg mx-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shadow-2xl rounded-none overflow-y-auto relative max-h-[95vh] transition-colors duration-300" (click)="$event.stopPropagation()">
      <!-- Modal Header -->
      <div class="px-4 md:px-6 py-4 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 flex items-center justify-between sticky top-0 z-10 transition-colors duration-300">
        <h3 class="text-sm font-black text-slate-900 dark:text-white uppercase tracking-wider">
          {{ isEditMode ? 'Editar Datos del Alumno' : 'Registrar Nuevo Alumno' }}
        </h3>
        <button (click)="closeCreateEditModal()" class="text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300 flex transition-colors">
          <span class="material-symbols-outlined text-lg">close</span>
        </button>
      </div>

      <!-- Modal Form -->
      <form [formGroup]="alumnoForm" (ngSubmit)="onSubmit()" class="p-4 md:p-6 space-y-4">
        <!-- Error response display -->
        <div *ngIf="modalErrorMsg" class="flex items-start gap-2 bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-900 text-red-800 dark:text-red-300 p-3 rounded-none text-[11px] font-semibold transition-colors duration-300">
          <span class="material-symbols-outlined text-red-600 text-base">warning</span>
          <span>{{ modalErrorMsg }}</span>
        </div>

        <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
          <!-- Nombres -->
          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Nombres *</label>
            <input 
              formControlName="nombres" 
              type="text" 
              class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300">
            <p *ngIf="alumnoForm.get('nombres')?.hasError('required') && alumnoForm.get('nombres')?.touched" class="text-[10px] text-red-600 mt-1">El nombre es requerido.</p>
            <p *ngIf="alumnoForm.get('nombres')?.hasError('minlength') && alumnoForm.get('nombres')?.touched" class="text-[10px] text-red-600 mt-1">Debe tener al menos 2 caracteres.</p>
            <p *ngIf="alumnoForm.get('nombres')?.hasError('pattern') && alumnoForm.get('nombres')?.touched" class="text-[10px] text-red-600 mt-1">Solo se permiten letras.</p>
          </div>
          <!-- Apellidos -->
          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Apellidos *</label>
            <input 
              formControlName="apellidos" 
              type="text" 
              class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300">
            <p *ngIf="alumnoForm.get('apellidos')?.hasError('required') && alumnoForm.get('apellidos')?.touched" class="text-[10px] text-red-600 mt-1">El apellido es requerido.</p>
            <p *ngIf="alumnoForm.get('apellidos')?.hasError('minlength') && alumnoForm.get('apellidos')?.touched" class="text-[10px] text-red-600 mt-1">Debe tener al menos 2 caracteres.</p>
            <p *ngIf="alumnoForm.get('apellidos')?.hasError('pattern') && alumnoForm.get('apellidos')?.touched" class="text-[10px] text-red-600 mt-1">Solo se permiten letras.</p>
          </div>
        </div>

        <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
          <!-- Correo -->
          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Correo Electrónico *</label>
            <input 
              formControlName="correo" 
              type="email" 
              class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300">
            <p *ngIf="alumnoForm.get('correo')?.hasError('required') && alumnoForm.get('correo')?.touched" class="text-[10px] text-red-600 mt-1">El correo es requerido.</p>
            <p *ngIf="alumnoForm.get('correo')?.hasError('email') && alumnoForm.get('correo')?.touched" class="text-[10px] text-red-600 mt-1">Ingrese un correo válido.</p>
          </div>
          <!-- Telefono -->
          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Teléfono</label>
            <input 
              formControlName="telefono" 
              type="text" 
              class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300"
              placeholder="Ej. 999999999">
            <p *ngIf="alumnoForm.get('telefono')?.hasError('pattern') && alumnoForm.get('telefono')?.touched" class="text-[10px] text-red-600 mt-1">Debe tener exactamente 9 números.</p>
          </div>
        </div>

        <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
          <!-- Contraseña -->
          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">
              Contraseña {{ isEditMode ? '(opcional)' : '*' }}
            </label>
            <input 
              formControlName="password" 
              type="password" 
              class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300"
              placeholder="Mínimo 6 caracteres">
            <p *ngIf="alumnoForm.get('password')?.hasError('minlength') && alumnoForm.get('password')?.touched" class="text-[10px] text-red-600 mt-1">Mínimo 6 caracteres.</p>
            <p class="text-[10px] text-slate-500 dark:text-slate-400 mt-1">
              {{ isEditMode ? 'Déjala vacía si no deseas cambiarla.' : 'Si no la defines, se usará Alumno123! por defecto.' }}
            </p>
          </div>
          <div class="hidden md:block"></div>
        </div>

        <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
          <!-- Nivel de suscripcion -->
          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Nivel de Suscripción *</label>
            <select 
              formControlName="nivelSuscripcionId" 
              class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300">
              <option [value]="1">BÁSICO</option>
              <option [value]="2">INTERMEDIO</option>
              <option [value]="3">PREMIUM</option>
            </select>
          </div>
          <!-- Estado -->
          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Estado</label>
            <select 
              formControlName="estado" 
              class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300">
              <option [ngValue]="true">ACTIVO</option>
              <option [ngValue]="false">INACTIVO</option>
            </select>
          </div>
        </div>

        <!-- Form Buttons -->
        <div class="pt-4 border-t border-slate-100 dark:border-slate-800 flex flex-col-reverse gap-2 sm:flex-row sm:justify-end sm:gap-3">
          <button 
            type="button" 
            (click)="closeCreateEditModal()" 
            class="px-4 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-xs uppercase tracking-widest hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors rounded-none w-full sm:w-auto">
            Cancelar
          </button>
          <button 
            type="submit" 
            [disabled]="alumnoForm.invalid || isFormSubmitting" 
            class="px-4 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-widest hover:bg-slate-800 dark:hover:bg-slate-200 transition-colors rounded-none disabled:opacity-55 w-full sm:w-auto">
            {{ isFormSubmitting ? 'Guardando...' : 'Guardar Alumno' }}
          </button>
        </div>
      </form>
    </div>
  </div>

  <!-- Detail Modal -->
  <div *ngIf="showDetailModal && selectedAlumno" role="dialog" aria-modal="true" class="fixed inset-0 bg-slate-900/60 dark:bg-slate-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4" (click)="closeDetailModal()">
    <div class="w-full max-w-md mx-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shadow-2xl rounded-none overflow-y-auto max-h-[95vh] transition-colors duration-300" (click)="$event.stopPropagation()">
      <!-- Modal Header -->
      <div class="px-4 md:px-6 py-4 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 flex items-center justify-between sticky top-0 z-10 transition-colors duration-300">
        <h3 class="text-sm font-black text-slate-900 dark:text-white uppercase tracking-wider">Ficha Detallada del Alumno</h3>
        <button (click)="closeDetailModal()" class="text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300 transition-colors">
          <span class="material-symbols-outlined text-lg">close</span>
        </button>
      </div>

      <!-- Detail Body -->
      <div class="p-4 md:p-6 space-y-6">
        <div class="flex items-center gap-4 border-b border-slate-100 dark:border-slate-800 pb-4">
          <div class="w-14 h-14 bg-indigo-500/10 dark:bg-indigo-500/20 border border-indigo-500/20 dark:border-indigo-500/30 text-indigo-600 dark:text-indigo-400 flex items-center justify-center text-xl font-bold rounded-none shrink-0">
            {{ selectedAlumno.nombres.charAt(0) }}{{ selectedAlumno.apellidos.charAt(0) }}
          </div>
          <div>
            <h4 class="text-base font-black text-slate-900 dark:text-white leading-tight">{{ selectedAlumno.nombres }} {{ selectedAlumno.apellidos }}</h4>
            <span class="text-[10px] text-slate-400 dark:text-slate-500 uppercase tracking-wider font-bold">Código Alumno: ID-{{ selectedAlumno.id }}</span>
          </div>
        </div>

        <div class="space-y-4">
          <div class="grid grid-cols-1 sm:grid-cols-2 gap-3 text-xs">
            <div>
              <span class="block text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Correo</span>
              <span class="block font-medium text-slate-800 dark:text-slate-200 mt-0.5 break-all font-mono">{{ selectedAlumno.correo }}</span>
            </div>
            <div>
              <span class="block text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Teléfono</span>
              <span class="block font-medium text-slate-800 dark:text-slate-200 mt-0.5">{{ selectedAlumno.telefono || 'No registrado' }}</span>
            </div>
          </div>

          <div class="grid grid-cols-1 sm:grid-cols-2 gap-3 text-xs pt-2 border-t border-slate-100 dark:border-slate-800">
            <div>
              <span class="block text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Nivel Suscripción</span>
              <span [ngClass]="getSubscriptionClass(selectedAlumno.nivelSuscripcion)" class="inline-block px-2 py-0.5 text-[9px] font-black uppercase tracking-wider mt-1 rounded-none">
                {{ selectedAlumno.nivelSuscripcion }}
              </span>
            </div>
            <div>
              <span class="block text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Estado Cuenta</span>
              <span [ngClass]="selectedAlumno.estado ? 'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900' : 'bg-red-50 text-red-700 border-red-200 dark:bg-red-950/30 dark:text-red-450 dark:border-red-900'" class="inline-block px-2 py-0.5 text-[9px] font-black uppercase tracking-wider border mt-1 rounded-none">
                {{ selectedAlumno.estado ? 'ACTIVO' : 'INACTIVO' }}
              </span>
            </div>
          </div>
        </div>

        <div class="pt-4 border-t border-slate-100 dark:border-slate-800 flex justify-end">
          <button 
            type="button" 
            (click)="closeDetailModal()" 
            class="px-4 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-widest hover:bg-slate-800 dark:hover:bg-slate-200 transition-colors rounded-none w-full sm:w-auto">
            Cerrar Ficha
          </button>
        </div>
      </div>
    </div>
  </div>

  <!-- Confirm modal -->
  <app-confirm-modal
    [visible]="showConfirmModal"
    [type]="confirmModalType"
    [title]="confirmModalTitle"
    [message]="confirmModalMessage"
    confirmText="Confirmar"
    (onConfirm)="confirmAction()"
    (onCancel)="showConfirmModal = false">
  </app-confirm-modal>

</div>
